parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "VideoScriptsRoot",
  "type": "object",
  "required": [
    "video_scripts"
  ],
  "properties": {
    "video_scripts": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "estimated_duration_seconds",
          "full_script",
          "hook",
          "video_number",
          "visual_instructions",
          "word_count",
          "working_title"
        ],
        "properties": {
          "estimated_duration_seconds": {
            "type": "integer",
            "description": "The estimated length of the video in seconds."
          },
          "full_script": {
            "type": "string",
            "description": "The complete spoken narration or dialogue for the video."
          },
          "hook": {
            "type": "string",
            "description": "The opening line designed to grab the viewer's attention."
          },
          "video_number": {
            "type": "integer",
            "description": "The sequential identifier for the video."
          },
          "visual_instructions": {
            "type": "array",
            "description": "A list of scenes, camera angles, or text overlays to be shown visually.",
            "items": {
              "type": "string"
            }
          },
          "word_count": {
            "type": "integer",
            "description": "The total number of words in the full script."
          },
          "working_title": {
            "type": "string",
            "description": "The internal title for the video project."
          }
        }
      }
    }
  }
}

parameters.jsCode:
const trackToText = (track) => {
  return track.transcript.map(t => t.text.replace(/[\r\n]/gm, '')).join(' ');
}
return $input.all().reduce((acc, cur) => ({...acc, [cur.json.id]: trackToText(cur.json.tracks[0])}), {})
